;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@barrel
@eval exp='game.curTarget.addParam("intellect", 2)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Intelligence permanently increased by 2!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@delevent
@se f=kacha
@wait time=800
@se f=fence
@switchfence x=0 y=11 way=n mode=open
@wait time=800
@notice text="I heard a door open somewhere!"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="I must find a way to fight off sleepiness, or I will rot away in the depths of the labyrinth."

[eventoff]
;-------------------------------------------------------------------------------
